import pytest
from playwright.sync_api import sync_playwright

def test_chat_command_router_repair():
    with sync_playwright() as p:
        browser = p.chromium.launch()
        page = browser.new_page()
        page.set_content("""
        <html><head><meta charset=\"utf-8\"/></head><body>
        <div id=\"chat-container\">
          <div contenteditable=\"true\" data-testid=\"chat-input\" style=\"border:1px solid #000; padding:4px; min-height:20px;\"></div>
          <button id=\"send-button\" aria-label=\"Отправить\">Отправить</button>
        </div>
        <script>
          window.lastMessage = null;
          document.getElementById('send-button').addEventListener('click', () => {
            const input = document.querySelector('[data-testid=\"chat-input\"]');
            const msg = input ? (input.textContent || '') : '';
            if (msg.trim() === 'Ку') window.lastMessage = 'recognized_k_u';
            else window.lastMessage = 'unknown';
          });
        </script>
        </body></html>
        """")
        # Inject the patched chatRouter logic into the page context
        page.evaluate("""
        window.chatRouter = async function(message) {
          let input =
            document.querySelector('#chat-input') ||
            document.querySelector('textarea[aria-label="Сообщение"]') ||
            document.querySelector('[contenteditable="true"][data-testid="chat-input"]');
          if (input) {
            const tagName = input.tagName.toLowerCase();
            if (tagName === 'div' || tagName === 'span' || tagName === 'p') {
              input.textContent = message;
            } else {
              input.value = message;
            }
            input.dispatchEvent(new Event('input', { bubbles: true }));
          } else {
            const el = document.querySelector('[contenteditable="true"][data-testid="chat-input"]');
            if (el) { el.textContent = message; el.dispatchEvent(new Event('input', { bubbles: true })); }
          }
          const sendBtn = document.querySelector('#send-button')
            || document.querySelector('button:has-text("Отправить")')
            || document.querySelector('[aria-label="Отправить"]');
          if (sendBtn) sendBtn.click();
        };
        """
        )
        page.evaluate("window.chatRouter('Ку');")
        result = page.evaluate("window.lastMessage")
        assert result == 'recognized_k_u'
        browser.close()

