+// Utility to replay the last step deterministically on hh.ru automation
+export async function replayLastStep(page, lastStep) {
+  // If a lastStep descriptor is provided, attempt to re-run it
+  if (lastStep && lastStep.selector) {
+    const el = await page.$(lastStep.selector);
+    if (el) {
+      await el.click();
+      return await page.waitForLoadState('networkidle');
+    }
+  }
+  // Fallback: if known action, emulate by typing into the search box and submitting
+  if (lastStep && lastStep.action === 'search') {
+    await page.fill('input[name="text"]', lastStep.query || 'Python');
+    await page.press('input[name="text"]', 'Enter');
+    return await page.waitForLoadState('networkidle');
+  }
